import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { baiDangAPI, yeuCauAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './ChiTietBaiDang.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n);

export default function ChiTietBaiDang() {
  const { id } = useParams();
  const { user } = useAuthStore();
  const navigate = useNavigate();
  const [bd, setBd] = useState(null);
  const [loading, setLoading] = useState(true);
  const [applying, setApplying] = useState(false);
  const [moTaYeuCau, setMoTaYeuCau] = useState('');
  const [showApply, setShowApply] = useState(false);
  const [imgIdx, setImgIdx] = useState(0);

  useEffect(() => {
    baiDangAPI.layChiTiet(id)
      .then(r => setBd(r.data.data))
      .catch(() => toast.error('Không tìm thấy bài đăng'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleApply = async () => {
    if (!user) { navigate('/dang-nhap'); return; }
    if (!user.xacThuc) { toast.error('Bạn cần xác thực CCCD trước khi apply!'); navigate('/xac-thuc'); return; }
    setApplying(true);
    try {
      await yeuCauAPI.gui({ maPhong: bd.maPhong, moTa: moTaYeuCau });
      toast.success('Đã gửi yêu cầu tham gia!');
      setShowApply(false);
    } catch (e) {
      toast.error(e.response?.data?.message || 'Gửi yêu cầu thất bại');
    }
    setApplying(false);
  };

  if (loading) return <div className="spinner" />;
  if (!bd) return <div className="container page-wrapper"><div className="alert alert-danger">Không tìm thấy bài đăng.</div></div>;

  const imgs = bd.images || [];

  return (
    <div className="container page-wrapper">
      <div className="chitiet-layout">
        {/* Left: images + info */}
        <div>
          {/* Image gallery */}
          <div className="gallery">
            <div className="gallery-main">
              {imgs.length > 0
                ? <img src={imgs[imgIdx]} alt="Phòng" />
                : <div className="gallery-placeholder">🏠</div>
              }
            </div>
            {imgs.length > 1 && (
              <div className="gallery-thumbs">
                {imgs.map((img, i) => (
                  <img key={i} src={img} alt="" className={i === imgIdx ? 'active' : ''}
                    onClick={() => setImgIdx(i)} />
                ))}
              </div>
            )}
          </div>

          {/* Details card */}
          <div className="card" style={{ marginTop: 24 }}>
            <div className="card-body">
              <h1 className="chitiet-title">{bd.moTa}</h1>
              <div className="chitiet-price">{fmt(bd.giaTien)}/tháng</div>
              <div className="chitiet-address">📍 {bd.diaChi}</div>

              {bd.noiDung && (
                <div className="chitiet-content">
                  <h3>Mô tả chi tiết</h3>
                  <p>{bd.noiDung}</p>
                </div>
              )}

              {bd.maPhong && (
                <div className="chitiet-phong-info">
                  <h3>Thông tin phòng</h3>
                  <p>Mã phòng: #{bd.maPhong}</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right: poster + action */}
        <div>
          <div className="card poster-card">
            <div className="card-body">
              <h3 style={{ marginBottom: 16 }}>Người đăng</h3>
              <div className="poster-info">
                <img
                  src={bd.avatarNguoiDang || `https://ui-avatars.com/api/?name=${encodeURIComponent(bd.tenNguoiDang || 'U')}&background=FF6B35&color=fff&size=60`}
                  className="avatar avatar-lg" alt="" />
                <div>
                  <div style={{ fontWeight: 700, fontSize: 18 }}>{bd.tenNguoiDang}</div>
                  <span className="badge badge-success" style={{ marginTop: 4 }}>✓ Đã xác thực</span>
                </div>
              </div>

              <div style={{ marginTop: 20 }}>
                <div className="info-row"><span>👁️ Lượt xem</span><strong>{bd.soLuotXem}</strong></div>
                <div className="info-row"><span>📅 Ngày đăng</span><strong>{bd.ngayDang ? new Date(bd.ngayDang).toLocaleDateString('vi-VN') : ''}</strong></div>
                <div className="info-row">
                  <span>Trạng thái</span>
                  <span className={`badge ${bd.trangThai === 'Dang' ? 'badge-success' : 'badge-gray'}`}>
                    {bd.trangThai === 'Dang' ? 'Đang đăng' : bd.trangThai}
                  </span>
                </div>
              </div>

              {user?.maNguoiDung !== bd.maNguoiDang && bd.maPhong && (
                <div style={{ marginTop: 20 }}>
                  {!showApply ? (
                    <button className="btn btn-primary btn-block btn-lg" onClick={() => setShowApply(true)}>
                      🤝 Apply vào phòng này
                    </button>
                  ) : (
                    <div>
                      <textarea className="form-control" rows={3} placeholder="Giới thiệu bản thân..."
                        value={moTaYeuCau} onChange={e => setMoTaYeuCau(e.target.value)} style={{ marginBottom: 10 }} />
                      <div style={{ display:'flex', gap: 8 }}>
                        <button className="btn btn-primary" style={{ flex:1 }} onClick={handleApply} disabled={applying}>
                          {applying ? '⏳...' : '✅ Gửi yêu cầu'}
                        </button>
                        <button className="btn btn-secondary" onClick={() => setShowApply(false)}>Hủy</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
